export default {
  name: 'SwiperItem',
  props: {
    itemId: {
      type: String,
      default: '',
    },
  },
  mounted() {
    const { $el } = this;
    $el.style.position = 'absolute';
    $el.style.width = '100%';
    $el.style.height = '100%';
    const callbacks = this.$vnode._callbacks;
    if (callbacks) {
      callbacks.forEach((callback) => {
        callback();
      });
    }
  },
};
